    std::cout << Color::BLUE << "\xe2\x95\x91 " << Color::RESET << "  Total Power Generated: "
              << std::fixed << std::setprecision(0) << std::setw(5) << state.totalPowerGenerated << " units"
              << std::setw(22) << "" << Color::BLUE << "\xe2\x95\x91" << Color::RESET << "\n";

    std::cout << Color::BLUE << "\xe2\x95\x91 " << Color::RESET << Color::BOLD << "SAFETY METRICS:" << Color::RESET
              << std::setw(44) << "" << Color::BLUE << "\xe2\x95\x91" << Color::RESET << "\n";
    std::cout << Color::BLUE << "\xe2\x95\x91 " << Color::RESET << "  Lowest Coolant: "
              << std::fixed << std::setprecision(1) << std::setw(12) << state.lowestCoolant << "%"
              << std::setw(26) << "" << Color::BLUE << "\xe2\x95\x91" << Color::RESET << "\n";
    std::cout << Color::BLUE << "\xe2\x95\x91 " << Color::RESET << "  Highest Xenon: "
              << std::fixed << std::setprecision(1) << std::setw(13) << state.highestXenon << "%"
              << std::setw(26) << "" << Color::BLUE << "\xe2\x95\x91" << Color::RESET << "\n";
    std::cout << Color::BLUE << "\xe2\x95\x91 " << Color::RESET << "  Critical Events: "
              << std::setw(11) << state.criticalEvents
              << std::setw(28) << "" << Color::BLUE << "\xe2\x95\x91" << Color::RESET << "\n";

    // Calculate efficiency rating
    double efficiency = 0.0;
    if (state.turns > 0) {
        double tempEfficiency = 1.0 - (state.averageTemperature / state.currentDifficulty.meltdownTemperature);
        double safetyRating = 1.0 - (static_cast<double>(state.scramCount) / std::max(1, state.turns));
        double powerRating = state.totalElectricityGenerated / std::max(1, state.turns);
        efficiency = (tempEfficiency * 0.3 + safetyRating * 0.4 + std::min(1.0, powerRating / 100.0) * 0.3) * 100.0;
    }

    std::string efficiencyRating;
    std::string efficiencyColor;
    if (efficiency >= 80) { efficiencyRating = "EXCELLENT"; efficiencyColor = Color::GREEN; }
    else if (efficiency >= 60) { efficiencyRating = "GOOD"; efficiencyColor = Color::GREEN; }
    else if (efficiency >= 40) { efficiencyRating = "AVERAGE"; efficiencyColor = Color::YELLOW; }
    else if (efficiency >= 20) { efficiencyRating = "POOR"; efficiencyColor = Color::RED; }
    else { efficiencyRating = "CRITICAL"; efficiencyColor = Color::RED; }

    std::cout << Color::BLUE << "\xe2\x95\xa0\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\xa3" << Color::RESET << "\n";
    std::cout << Color::BLUE << "\xe2\x95\x91 " << Color::RESET << Color::BOLD << "OPERATOR EFFICIENCY: " << Color::RESET
              << efficiencyColor << std::fixed << std::setprecision(1) << efficiency << "% - " << efficiencyRating
              << Color::RESET << std::setw(25 - static_cast<int>(efficiencyRating.length())) << "" << Color::BLUE << "\xe2\x95\x91" << Color::RESET << "\n";

    std::cout << Color::BOLD << Color::BLUE
              << "\xe2\x95\x9a\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x90\xe2\x95\x9d"
              << Color::RESET << "\n\n";

