void Renderer::drainMessages(ReactorState& state) {
    for (const auto& msg : state.messages) {
        std::cout << msg.text;
        if (msg.triggerSound) Sound::beep();
        if (msg.triggerAlert) Sound::alert();
    }
    state.clearMessages();
}
